import { useState, useEffect } from 'react'
import { Link } from 'react-router-dom'
import ProductCard from '../components/ProductCard'
import { getProducts } from '../data/products'
import '../styles/ManageInventory.css'

const STATUS_OPTIONS = [
  { value: 'available', label: 'Có sẵn' },
  { value: 'rented', label: 'Đã thuê' },
  { value: 'maintenance', label: 'Bảo trì' },
  { value: 'sold', label: 'Đã bán' }
]

function ManageInventory() {
  const [products, setProducts] = useState([])
  const [editingId, setEditingId] = useState(null)
  const [editData, setEditData] = useState({ quantity: '', status: '' })

  // Load products
  useEffect(() => {
    const data = getProducts()
    // Add quantity and status for demo (normally from backend)
    const productsWithInventory = data.map(p => ({
      ...p,
      quantity: Math.floor(Math.random() * 10) + 1,
      status: 'available'
    }))
    setProducts(productsWithInventory)
  }, [])

  const handleEdit = (product) => {
    setEditingId(product.id)
    setEditData({
      quantity: product.quantity,
      status: product.status
    })
  }

  const handleSave = (id) => {
    setProducts(prev => prev.map(p =>
      p.id === id ? { ...p, ...editData } : p
    ))
    setEditingId(null)
  }

  const handleCancel = () => {
    setEditingId(null)
    setEditData({ quantity: '', status: '' })
  }

  const handleSell = (id) => {
    // TODO: Mark as sold
    alert('Sản phẩm đã được đăng bán!')
  }

  return (
    <div className="manage-inventory-page">
      {/* ═════ HEADER ═════ */}
      <header className="manage-inventory-header">
        <span className="manage-inventory-label">✦ Quản Lý Kho</span>
        <h1 className="manage-inventory-title">Kho Trang Phục Cosplay</h1>
        <p className="manage-inventory-subtitle">
          Quản lý số lượng, tình trạng và đăng bán các trang phục của bạn.
        </p>
        <Link to="/add-product" className="btn-add-product">
          + Thêm Sản Phẩm Mới
        </Link>
      </header>

      {/* ═════ INVENTORY LIST ═════ */}
      <div className="inventory-list">
        {products.length > 0 ? (
          <div className="inventory-grid">
            {products.map(product => (
              <div key={product.id} className="inventory-item">
                <div className="product-preview">
                  <ProductCard product={product} />
                </div>

                <div className="inventory-details">
                  <div className="detail-row">
                    <span className="label">Số lượng:</span>
                    {editingId === product.id ? (
                      <input
                        type="number"
                        value={editData.quantity}
                        onChange={(e) => setEditData(prev => ({ ...prev, quantity: e.target.value }))}
                        min="0"
                        className="edit-input"
                      />
                    ) : (
                      <span className="value">{product.quantity}</span>
                    )}
                  </div>

                  <div className="detail-row">
                    <span className="label">Tình trạng:</span>
                    {editingId === product.id ? (
                      <select
                        value={editData.status}
                        onChange={(e) => setEditData(prev => ({ ...prev, status: e.target.value }))}
                        className="edit-select"
                      >
                        {STATUS_OPTIONS.map(opt => (
                          <option key={opt.value} value={opt.value}>{opt.label}</option>
                        ))}
                      </select>
                    ) : (
                      <span className={`status ${product.status}`}>
                        {STATUS_OPTIONS.find(s => s.value === product.status)?.label}
                      </span>
                    )}
                  </div>

                  <div className="actions">
                    {editingId === product.id ? (
                      <>
                        <button onClick={() => handleSave(product.id)} className="btn-save">
                          Lưu
                        </button>
                        <button onClick={handleCancel} className="btn-cancel">
                          Hủy
                        </button>
                      </>
                    ) : (
                      <>
                        <button onClick={() => handleEdit(product)} className="btn-edit">
                          Chỉnh sửa
                        </button>
                        <button onClick={() => handleSell(product.id)} className="btn-sell">
                          Đăng bán
                        </button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="inventory-empty">
            <div className="empty-icon"></div>
            <h3>Kho trống</h3>
            <p>Bạn chưa có sản phẩm nào trong kho.</p>
            <Link to="/add-product" className="btn-add-first">
              Thêm Sản Phẩm Đầu Tiên
            </Link>
          </div>
        )}
      </div>
    </div>
  )
}

export default ManageInventory

.add-product-page {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 0;
  max-width: 800px;
  margin: 0 auto;
  padding: 0 24px;
}

/* ═══ HEADER ═══ */
.add-product-header {
  text-align: center;
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 40px 0 32px;
  border-bottom: 1px solid var(--color-border);
  margin-bottom: 32px;
}

.add-product-label {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-purple-pale);
}

.add-product-title {
  font-family: var(--font-display);
  font-size: clamp(32px, 5vw, 48px);
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: -0.01em;
  line-height: 1;
  margin: 0;
}

.add-product-subtitle {
  font-size: 15px;
  color: var(--text-secondary);
  max-width: 560px;
  margin: 0 auto;
  line-height: 1.7;
}

/* ═══ FORM ═══ */
.add-product-form {
  display: flex;
  flex-direction: column;
  gap: 24px;
  margin-bottom: 40px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.form-group label {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.form-group input,
.form-group textarea,
.form-group select {
  background: rgba(15, 6, 32, 0.8);
  border: 1px solid var(--color-border);
  border-radius: 8px;
  padding: 12px 16px;
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 14px;
  outline: none;
  transition: var(--transition);
}

.form-group input::placeholder,
.form-group textarea::placeholder {
  color: var(--text-muted);
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
  border-color: var(--color-border-bright);
  box-shadow: 0 0 0 3px rgba(124, 58, 237, 0.1);
  background: rgba(15, 6, 32, 0.95);
}

.form-group textarea {
  resize: vertical;
  min-height: 100px;
}

.form-group select {
  cursor: pointer;
  appearance: none;
  background-image: url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%23c4aeda' stroke-width='2'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e");
  background-repeat: no-repeat;
  background-position: right 12px center;
  background-size: 16px;
  padding-right: 40px;
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}

.btn-submit {
  padding: 16px 32px;
  background: linear-gradient(135deg, var(--color-purple), var(--color-purple-mid));
  border: none;
  border-radius: 8px;
  color: #fff;
  font-family: var(--font-body);
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  box-shadow: 0 4px 16px rgba(124, 58, 237, 0.5);
  align-self: flex-start;
}

.btn-submit:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(124, 58, 237, 0.7);
}

/* ═══ RESPONSIVE ═══ */
@media (max-width: 768px) {
  .add-product-page {
    padding: 0 16px;
  }

  .form-row {
    grid-template-columns: 1fr;
    gap: 16px;
  }

  .btn-submit {
    align-self: stretch;
  }
}

.home {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 0;
}

/* ===================== HERO ===================== */
.hero {
  position: relative;
  min-height: 90vh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 100px 24px 80px;
  overflow: hidden;
  background: linear-gradient(135deg, rgba(7, 3, 15, 0.95), rgba(15, 6, 32, 0.98));
  border: none;
  border-radius: 0;
}

/* Animated orbs */
.hero-bg-orbs { position: absolute; inset: 0; pointer-events: none; }

.orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(60px);
  animation: orbFloat 8s ease-in-out infinite;
}

.orb-1 {
  width: 500px; height: 500px;
  top: -150px; left: -150px;
  background: radial-gradient(circle, rgba(124, 58, 237, 0.25) 0%, transparent 70%);
  animation-delay: 0s;
}

.orb-2 {
  width: 400px; height: 400px;
  top: -100px; right: -100px;
  background: radial-gradient(circle, rgba(236, 72, 153, 0.15) 0%, transparent 70%);
  animation-delay: -3s;
}

.orb-3 {
  width: 300px; height: 300px;
  bottom: -100px; left: 50%;
  transform: translateX(-50%);
  background: radial-gradient(circle, rgba(168, 85, 247, 0.2) 0%, transparent 70%);
  animation-delay: -5s;
}

@keyframes orbFloat {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(20px, -20px) scale(1.05); }
  66% { transform: translate(-15px, 15px) scale(0.97); }
}

/* Hero content */
.hero-content {
  position: relative;
  z-index: 2;
  max-width: 720px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 28px;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 24px;
  border-radius: 50px;
  border: 1px solid rgba(200, 132, 252, 0.3);
  background: rgba(124, 58, 237, 0.12);
  color: var(--color-purple-pale);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  backdrop-filter: blur(12px);
}

.hero-title {
  font-family: var(--font-display);
  font-size: clamp(42px, 7vw, 80px);
  font-weight: 700;
  line-height: 1.08;
  letter-spacing: -0.02em;
  color: var(--text-primary);
  margin: 0;
}

.hero-title-gradient {
  background: linear-gradient(135deg, #c084fc 0%, #f0abfc 40%, #a855f7 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  display: block;
}

.hero-subtitle {
  font-size: clamp(6px, 2.2vw, 20px);
  color: var(--text-secondary);
  line-height: 1.8;
  max-width: 600px;
  font-weight: 400;
}

/* Buttons */
.hero-actions {
  display: flex;
  gap: 16px;
  align-items: center;
  flex-wrap: wrap;
  justify-content: center;
}

.btn-hero-primary {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 14px 32px;
  background: linear-gradient(135deg, var(--color-purple), var(--color-purple-mid));
  color: #fff;
  text-decoration: none;
  border-radius: 50px;
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: 600;
  transition: var(--transition);
  box-shadow: 0 6px 24px rgba(124, 58, 237, 0.5), inset 0 1px 0 rgba(255,255,255,0.1);
}

.btn-hero-primary:hover {
  transform: translateY(-3px);
  box-shadow: 0 12px 36px rgba(124, 58, 237, 0.7);
  background: linear-gradient(135deg, #8b47f0, #a840fb);
}

.btn-hero-primary svg {
  transition: transform 0.2s ease;
}

.btn-hero-primary:hover svg {
  transform: translateX(4px);
}

.btn-hero-outline {
  display: inline-flex;
  align-items: center;
  padding: 13px 30px;
  border: 1px solid var(--color-border-bright);
  background: rgba(124, 58, 237, 0.06);
  color: var(--color-purple-pale);
  text-decoration: none;
  border-radius: 50px;
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: 500;
  transition: var(--transition);
  backdrop-filter: blur(8px);
}

.btn-hero-outline:hover {
  background: rgba(124, 58, 237, 0.15);
  border-color: var(--color-purple-light);
  transform: translateY(-2px);
}

/* Stats */
.hero-stats {
  display: flex;
  align-items: center;
  gap: 28px;
  padding-top: 8px;
}

.hero-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.hero-stat-num {
  font-family: var(--font-display);
  font-size: 26px;
  font-weight: 600;
  background: linear-gradient(135deg, var(--color-purple-pale), var(--color-accent));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.hero-stat-label {
  font-size: 11px;
  color: var(--text-muted);
  letter-spacing: 0.08em;
}

.hero-stat-sep {
  width: 1px;
  height: 36px;
  background: var(--color-border);
}

/* ===================== FEATURES ===================== */
.features {
  padding: 80px 24px;
  background: var(--bg-secondary);
  border-top: 1px solid var(--color-border);
}

.section-header {
  text-align: center;
  margin-bottom: 50px;
}

.section-label {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-purple-pale);
  margin-bottom: 8px;
}

.section-title {
  font-family: var(--font-display);
  font-size: clamp(32px, 5vw, 48px);
  font-weight: 700;
  color: var(--text-primary);
  margin: 0;
  letter-spacing: -0.01em;
}

.features-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 32px;
  max-width: 1320px;
  margin: 0 auto;
}

.feature-card {
  padding: 32px 24px;
  background: var(--bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  text-align: center;
  transition: var(--transition);
  position: relative;
}

.feature-card::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 50% 0%, rgba(124, 58, 237, 0.1) 0%, transparent 70%);
  border-radius: var(--radius-lg);
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
}

.feature-card:hover {
  transform: translateY(-4px);
  border-color: var(--color-border-bright);
  background: var(--bg-card-hover);
  box-shadow: 0 12px 40px rgba(124, 58, 237, 0.15);
}

.feature-card:hover::before {
  opacity: 1;
}

.feature-icon {
  font-size: 40px;
  margin-bottom: 16px;
  line-height: 1;
  filter: drop-shadow(0 0 8px rgba(168, 85, 247, 0.4));
}

.feature-title {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: 12px;
  letter-spacing: 0.01em;
}

.feature-desc {
  font-size: 14px;
  color: var(--text-muted);
  line-height: 1.7;
  margin: 0;
}

/* ===================== CTA BANNER ===================== */
.cta-banner {
  position: relative;
  padding: 80px 24px;
  background: linear-gradient(135deg, rgba(124, 58, 237, 0.12) 0%, rgba(236, 72, 153, 0.06) 100%);
  border: 1px solid var(--color-border);
  border-top: none;
  overflow: hidden;
}

.cta-glow {
  position: absolute;
  top: -80px;
  right: -100px;
  width: 400px;
  height: 400px;
  background: radial-gradient(circle, rgba(168, 85, 247, 0.15) 0%, transparent 70%);
  border-radius: 50%;
  filter: blur(60px);
  pointer-events: none;
}

.cta-content {
  position: relative;
  z-index: 2;
  max-width: 600px;
  margin: 0 auto;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 28px;
}

.cta-title {
  font-family: var(--font-display);
  font-size: clamp(28px, 4vw, 42px);
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.1;
  margin: 0;
  letter-spacing: -0.01em;
}

.cta-sub {
  font-size: 16px;
  color: var(--text-secondary);
  line-height: 1.7;
  margin: 0;
}

/* Responsive */
@media (max-width: 768px) {
  .home { gap: 60px; }
  .hero { min-height: 60vh; padding: 60px 20px 48px; }
  .hero-stats { gap: 16px; }
  .hero-stat-num { font-size: 20px; }
  .features-grid { grid-template-columns: 1fr; }
  .cta-banner { padding: 48px 24px; }
}

@media (max-width: 480px) {
  .hero-actions { flex-direction: column; width: 100%; }
  .btn-hero-primary, .btn-hero-outline { width: 100%; justify-content: center; }
}

