  font-family: var(--font-body);
  font-size: 14px;
  font-weight: 500;
  transition: var(--transition);
  backdrop-filter: blur(8px);
}

.btn-hero-secondary:hover {
  background: rgba(15, 6, 32, 0.95);
  border-color: var(--color-border-bright);
  color: var(--text-primary);
  transform: translateY(-2px);
}

/* Stats */
.hero-stats {
  display: flex;
  align-items: center;
  gap: 28px;
  padding-top: 8px;
}

.hero-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.hero-stat-num {
  font-family: var(--font-display);
  font-size: 26px;
  font-weight: 600;
  background: linear-gradient(135deg, var(--color-purple-pale), var(--color-accent));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.hero-stat-label {
  font-size: 11px;
  color: var(--text-muted);
  letter-spacing: 0.08em;
}

.hero-stat-sep {
  width: 1px;
  height: 36px;
  background: var(--color-border);
}

/* ===================== FEATURES ===================== */
.features {
  padding: 80px 24px;
  background: var(--bg-secondary);
  border-top: 1px solid var(--color-border);
}

.section-header {
  text-align: center;
  margin-bottom: 50px;
}

.section-label {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-purple-pale);
  margin-bottom: 8px;
}

.section-title {
  font-family: var(--font-display);
  font-size: clamp(32px, 5vw, 48px);
  font-weight: 700;
  color: var(--text-primary);
  margin: 0;
  letter-spacing: -0.01em;
}

.features-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 32px;
  max-width: 1320px;
  margin: 0 auto;
}

.feature-card {
  padding: 32px 24px;
  background: var(--bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  text-align: center;
  transition: var(--transition);
  position: relative;
}

.feature-card::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 50% 0%, rgba(124, 58, 237, 0.1) 0%, transparent 70%);
  border-radius: var(--radius-lg);
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
}

.feature-card:hover {
  transform: translateY(-4px);
  border-color: var(--color-border-bright);
  background: var(--bg-card-hover);
  box-shadow: 0 12px 40px rgba(124, 58, 237, 0.15);
}

.feature-card:hover::before {
  opacity: 1;
}

.feature-icon {
  font-size: 40px;
  margin-bottom: 16px;
  line-height: 1;
  filter: drop-shadow(0 0 8px rgba(168, 85, 247, 0.4));
}

.feature-title {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: 12px;
  letter-spacing: 0.01em;
}

.feature-desc {
  font-size: 14px;
  color: var(--text-muted);
  line-height: 1.7;
  margin: 0;
}

/* ===================== CTA BANNER ===================== */
.cta-banner {
  position: relative;
  padding: 80px 24px;
  background: linear-gradient(135deg, rgba(124, 58, 237, 0.12) 0%, rgba(236, 72, 153, 0.06) 100%);
  border: 1px solid var(--color-border);
  border-top: none;
  overflow: hidden;
}

.cta-glow {
  position: absolute;
  top: -80px;
  right: -100px;
  width: 400px;
  height: 400px;
  background: radial-gradient(circle, rgba(168, 85, 247, 0.15) 0%, transparent 70%);
  border-radius: 50%;
  filter: blur(60px);
  pointer-events: none;
}

.cta-content {
  position: relative;
  z-index: 2;
  max-width: 600px;
  margin: 0 auto;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 28px;
}

.cta-title {
  font-family: var(--font-display);
  font-size: clamp(28px, 4vw, 42px);
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.1;
  margin: 0;
  letter-spacing: -0.01em;
}

.cta-sub {
  font-size: 16px;
  color: var(--text-secondary);
  line-height: 1.7;
  margin: 0;
}

/* Responsive */
@media (max-width: 768px) {
  .home { gap: 60px; }
  .hero { min-height: 60vh; padding: 60px 20px 48px; }
  .hero-stats { gap: 16px; }
  .hero-stat-num { font-size: 20px; }
  .features-grid { grid-template-columns: 1fr; }
  .cta-banner { padding: 48px 24px; }
}

@media (max-width: 480px) {
  .hero-actions { flex-direction: column; width: 100%; }
  .btn-hero-primary, .btn-hero-outline, .btn-hero-secondary { width: 100%; justify-content: center; }
}

.manage-inventory-page {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 0;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
}

/* ═══ HEADER ═══ */
.manage-inventory-header {
  text-align: center;
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 40px 0 32px;
  border-bottom: 1px solid var(--color-border);
  margin-bottom: 32px;
  position: relative;
}

.manage-inventory-label {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-purple-pale);
}

.manage-inventory-title {
  font-family: var(--font-display);
  font-size: clamp(32px, 5vw, 48px);
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: -0.01em;
  line-height: 1;
  margin: 0;
}

.manage-inventory-subtitle {
  font-size: 15px;
  color: var(--text-secondary);
  max-width: 560px;
  margin: 0 auto;
  line-height: 1.7;
}

.btn-add-product {
  position: absolute;
  top: 40px;
  right: 0;
  padding: 10px 20px;
  background: linear-gradient(135deg, var(--color-purple), var(--color-purple-mid));
  border: none;
  border-radius: 8px;
  color: #fff;
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: 600;
  text-decoration: none;
  cursor: pointer;
  transition: var(--transition);
  box-shadow: 0 4px 16px rgba(124, 58, 237, 0.5);
}

.btn-add-product:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(124, 58, 237, 0.7);
}

/* ═══ INVENTORY LIST ═══ */
.inventory-list {
  margin-bottom: 40px;
}

.inventory-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 24px;
}

.inventory-item {
  background: rgba(15, 6, 32, 0.7);
  border: 1px solid var(--color-border);
  border-radius: 12px;
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  transition: var(--transition);
}

.inventory-item:hover {
  border-color: var(--color-border-bright);
  background: rgba(15, 6, 32, 0.8);
}

.product-preview {
  flex-shrink: 0;
}

.inventory-details {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.detail-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
}

.detail-row .label {
  font-size: 14px;
  color: var(--text-secondary);
  font-weight: 500;
  flex-shrink: 0;
}

.detail-row .value {
  font-size: 14px;
  color: var(--text-primary);
  font-weight: 600;
}

.status {
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
}

.status.available {
  background: rgba(34, 197, 94, 0.2);
  color: #22c55e;
}

.status.rented {
  background: rgba(251, 191, 36, 0.2);
  color: #fbbf24;
}

.status.maintenance {
  background: rgba(239, 68, 68, 0.2);
  color: #ef4444;
}

.status.sold {
  background: rgba(156, 163, 175, 0.2);
  color: #9ca3af;
}

.edit-input,
.edit-select {
  background: rgba(15, 6, 32, 0.9);
  border: 1px solid var(--color-border-bright);
  border-radius: 4px;
  padding: 4px 8px;
  color: var(--text-primary);
  font-size: 14px;
  outline: none;
  width: 80px;
}

.edit-select {
  cursor: pointer;
  appearance: none;
  background-image: url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%23c4aeda' stroke-width='2'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e");
  background-repeat: no-repeat;
  background-position: right 4px center;
  background-size: 12px;
  padding-right: 20px;
}

.actions {
  display: flex;
  gap: 8px;
  margin-top: 8px;
}

.btn-edit,
.btn-save,
.btn-cancel,
.btn-sell {
  padding: 8px 12px;
  border: none;
  border-radius: 6px;
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.btn-edit {
  background: rgba(124, 58, 237, 0.2);
  color: var(--color-purple-pale);
  border: 1px solid var(--color-border);
}

.btn-edit:hover {
  background: rgba(124, 58, 237, 0.3);
}

.btn-save {
  background: rgba(34, 197, 94, 0.2);
  color: #22c55e;
  border: 1px solid rgba(34, 197, 94, 0.3);
}

.btn-save:hover {
  background: rgba(34, 197, 94, 0.3);
}

.btn-cancel {
  background: rgba(239, 68, 68, 0.2);
  color: #ef4444;
  border: 1px solid rgba(239, 68, 68, 0.3);
}

.btn-cancel:hover {
  background: rgba(239, 68, 68, 0.3);
}

.btn-sell {
  background: rgba(251, 191, 36, 0.2);
  color: #fbbf24;
  border: 1px solid rgba(251, 191, 36, 0.3);
}

.btn-sell:hover {
  background: rgba(251, 191, 36, 0.3);
}

/* Empty State */
.inventory-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 16px;
  padding: 100px 24px;
  text-align: center;
}

.empty-icon {
  font-size: 56px;
  opacity: 0.6;
}

.inventory-empty h3 {
  font-family: var(--font-display);
  font-size: 24px;
  color: var(--text-primary);
  margin: 0;
}

.inventory-empty p {
  font-size: 14px;
  color: var(--text-muted);
  max-width: 400px;
  margin: 0;
}

.btn-add-first {
  padding: 12px 28px;
  background: linear-gradient(135deg, var(--color-purple), var(--color-purple-mid));
  border: none;
  border-radius: 8px;
  color: #fff;
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: 600;
  text-decoration: none;
  cursor: pointer;
  transition: var(--transition);
  margin-top: 8px;
  box-shadow: 0 4px 16px rgba(124, 58, 237, 0.5);
}

.btn-add-first:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(124, 58, 237, 0.7);
}

/* ═══ RESPONSIVE ═══ */
@media (max-width: 768px) {
  .manage-inventory-page {
    padding: 0 16px;
  }

  .manage-inventory-header {
    padding: 24px 0 20px;
    margin-bottom: 20px;
  }

  .btn-add-product {
    position: static;
    margin-top: 16px;
    align-self: center;
  }

  .inventory-grid {
    grid-template-columns: 1fr;
    gap: 16px;
  }

  .inventory-item {
    padding: 16px;
  }

  .actions {
    flex-direction: column;
    gap: 6px;
  }

  .btn-edit,
  .btn-save,
  .btn-cancel,
  .btn-sell {
    width: 100%;
  }
}
